void setupDeepLinkHandler() async {
  try {
    final initialLink = await getInitialLink();
    if (initialLink != null) {
      handleDeepLink(initialLink);
    }

    linkStream.listen((link) {
      handleDeepLink(link);
    });
  } catch (e) {
    print('Error: $e');
