}

void handleDeepLink(String link) {
  final uri = Uri.parse(link);
  if (uri.host == 'profile') {
    Navigator.pushNamed(
      navigatorKey.currentContext!,
      '/profile',
      arguments: uri.pathSegments[1],
    );
  } else if (uri.host == 'payment' && uri.path == '/confirm') {
    Navigator.pushNamed(navigatorKey.currentContext!, '/payment/confirm');
  }
}